sql:
SELECT scenario_id, MAX(result) AS max_result
FROM scenario_results
GROUP BY scenario_id;

SELECT name
FROM water_treatment_plants
WHERE location = 'Location 1';

SELECT month, inflow
FROM inflows
WHERE reservoir_id = 0 AND month = 1;

SELECT name, capacity, current_level,
       AVG(current_level) OVER () AS average_current_level
FROM reservoirs;

SELECT name, current_level
FROM reservoirs
WHERE current_level > (SELECT value FROM parameter_values WHERE value_id = 0);

SELECT name, capacity
FROM water_treatment_plants
ORDER BY capacity DESC;

SELECT technology, AVG(capacity) AS average_capacity, MAX(capacity) AS max_capacity
FROM water_treatment_plants
GROUP BY technology;

external_knowledge:
- "Water intake" refers to the amount of water that flows into the reservoir; 
- "Peak energy usage" refers to the highest amount of energy consumed; 
- "Located near water treatment plants" means the reservoir's location matches the plant's location; 
- "Recorded energy consumption" refers to any non-zero energy usage data.

sql:
SELECT parameter, AVG(value) AS average_value
FROM water_quality
GROUP BY parameter;
